// $lib/actions/auth.js
import ApiClient from '$lib/api';
import { user, accessToken } from '$lib/stores/store';
import { clearRefreshToken } from '$lib/db/indexeddb'; // 📌 thêm dòng này
import { closeSocket } from '$lib/websocket-client';

const api = new ApiClient();

export async function logOut() {
    try {
        const data = await api.post('/auth/logout', {}, { withCredentials: true });
        user.set(null);
        accessToken.set(null);

        // close socket
        await closeSocket();

        // Xoá refresh token khỏi IndexedDB
        await clearRefreshToken();

        console.log('🔐 Logged out + refresh token cleared');

    } catch (err) {
        console.error('🚨 LOGOUT ERROR:', err);
    }
}
